window.B59_RECORDS = [{"id":"B59-0001","title":"Key Historical Milestones in Cryptography and Digital Currency","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"writing","description":"Comprehensive research timeline documenting 49 key events in the history of cryptography and digital currency from 1964 to 2008. Covers Paul Baran's distributed networks, public-key cryptography, David Chaum's blind signatures and DigiCash, the Cypherpunks, PGP, Crypto Wars, e-gold, Hashcash, b-money, bit gold, RPOW, and the Bitcoin whitepaper. Each entry includes date, event, project, individuals, location, description, and source references. 49 cited sources.","citation":"Project B59. (2026, May 24). \"Key Historical Milestones in Cryptography and Digital Currency.\" Research compilation generated via Google NotebookLM from 49 primary and secondary sources.","provenance":"Generated by Google NotebookLM as a structured data table from sources uploaded to the Project B59 research notebook. Sources include academic papers, Wikipedia articles, archived websites, and original research documents. This is a research compilation, not a primary source.","hash":"37c1ef5918b3cd5122e94e7280260d62205b2c90d7398a3d452a5c68b5ad2dcb","tags":["timeline","research-compilation","cryptography","digital-cash","cypherpunks","milestones"],"excerpt":null,"files":[{"path":"key-historical-milestones.ods","size":30957}],"content_path":"content/B59-0001"},{"id":"B59-0002","title":"Rise and Fall of DigiCash","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"video","description":"Video overview examining the rise and fall of DigiCash, David Chaum's pioneering electronic cash company founded in 1989 in Amsterdam. Covers the invention of blind signatures, the eCash protocol, CyberBucks trial, partnerships with Mark Twain Bank and Deutsche Bank, and the company's eventual bankruptcy in 1998 despite having solved the technical problems of digital cash years before the market was ready.","citation":"Project B59. (2026, May 24). \"Rise & Fall of DigiCash.\" Video overview generated via Google NotebookLM from collected research sources.","provenance":"AI-generated video overview produced by Google NotebookLM from sources in the Project B59 research notebook. Content synthesizes multiple primary and secondary sources on DigiCash history. This is a research compilation, not primary source footage.","hash":"100609291a0b1cb9f452a53bc6d7485e1e3748effcbaa31104842982e358bd9f","tags":["digicash","david-chaum","ecash","digital-cash","research-compilation"],"excerpt":null,"files":[{"path":"rise-fall-of-digicash.mp4","size":35788364}],"content_path":"content/B59-0002"},{"id":"B59-0003","title":"The Extropian Blueprint","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"video","description":"Video overview exploring the Extropian movement and its connections to cryptography, digital cash, and the cypherpunk ethos. Covers the founding of Extropy journal by Max More in 1988, the intellectual crossover between transhumanism and crypto-anarchy, and how Extropian ideas about technology, liberty, and self-sovereignty influenced the development of digital currency systems.","citation":"Project B59. (2026, May 24). \"The Extropian Blueprint.\" Video overview generated via Google NotebookLM from collected research sources.","provenance":"AI-generated video overview produced by Google NotebookLM from sources in the Project B59 research notebook. This is a research compilation, not primary source footage.","hash":"d2945b6797cc50b69f227659e6f34e81556118904ba36d0e6030ee8c13c1d788","tags":["extropians","transhumanism","crypto-anarchy","max-more","research-compilation"],"excerpt":null,"files":[{"path":"extropian-blueprint.mp4","size":53021555}],"content_path":"content/B59-0003"},{"id":"B59-0004","title":"The Phil Salin Story","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"video","description":"Video overview documenting the life and work of Phil Salin, a largely overlooked figure in the pre-history of digital markets and smart contracts. Covers Salin's work on the American Information Exchange (AMIX), his 1991 position paper arguing that software is protected speech under the First Amendment, his connections to the Agorics project applying Hayekian economics to computation, and his influence on the intellectual foundations that led to cryptocurrency.","citation":"Project B59. (2026, May 24). \"The Phil Salin Story.\" Video overview generated via Google NotebookLM from collected research sources.","provenance":"AI-generated video overview produced by Google NotebookLM from sources in the Project B59 research notebook including Phil Salin's original writings and the Agorics project documentation. This is a research compilation, not primary source footage.","hash":"252f794f56423fb182c6578935ec442d725bc647371b3873aac9dbc91ecad7b1","tags":["phil-salin","amix","agorics","digital-markets","free-speech","research-compilation"],"excerpt":null,"files":[{"path":"the-phil-salin-story.mp4","size":41882063}],"content_path":"content/B59-0004"},{"id":"B59-0005","title":"The Prophet Too Early","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"video","description":"Video overview exploring the story of visionaries in cryptography and digital cash who were ahead of their time. Examines figures whose ideas and implementations preceded mainstream adoption by decades, and the pattern of technical solutions arriving before the cultural and economic conditions necessary for their success.","citation":"Project B59. (2026, May 24). \"The Prophet Too Early.\" Video overview generated via Google NotebookLM from collected research sources.","provenance":"AI-generated video overview produced by Google NotebookLM from sources in the Project B59 research notebook. This is a research compilation, not primary source footage.","hash":"c360170b3da2bf939621ef55a7d47f12b94ab7388dfba23176f41516d5585efc","tags":["digital-cash","early-history","visionaries","research-compilation"],"excerpt":null,"files":[{"path":"the-prophet-too-early.mp4","size":46544939}],"content_path":"content/B59-0005"},{"id":"B59-0006","title":"The Cyber Blueprint","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"writing","description":"Research report examining the technological and ideological blueprint of the cypherpunk movement and its direct influence on the development of digital cash, privacy tools, and decentralized systems. Synthesizes material from the Cypherpunks Mailing List, academic papers, and historical accounts into a comprehensive overview of the technical lineage from cryptographic theory to practical implementation.","citation":"Project B59. (2026, May 24). \"The Cyber Blueprint.\" Research report generated via Google NotebookLM from collected primary and secondary sources.","provenance":"AI-generated research report produced by Google NotebookLM from sources in the Project B59 research notebook. This is a research compilation, not a primary source document.","hash":"2e54b34c2724bb770dea2d8b72bbcd009b0b379e6d956df399c92ad5fd6bdabe","tags":["cypherpunks","cryptography","digital-cash","research-compilation","technical-history"],"excerpt":null,"files":[{"path":"the-cyber-blueprint.pdf","size":13367781}],"content_path":"content/B59-0006"},{"id":"B59-0007","title":"1995 Extropian Blueprint","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"writing","description":"Research report focused on the Extropian movement circa 1995 and its intersections with cryptography, digital markets, and the emerging internet economy. Examines the intellectual environment that connected transhumanist philosophy with practical work on electronic cash, agoric computing, and digital liberty.","citation":"Project B59. (2026, May 24). \"1995 Extropian Blueprint.\" Research report generated via Google NotebookLM from collected primary and secondary sources.","provenance":"AI-generated research report produced by Google NotebookLM from sources in the Project B59 research notebook. This is a research compilation, not a primary source document.","hash":"16e35560bd08da677e5312d452b227e551ee3b5374c3b64986bcd67ecdd53dd2","tags":["extropians","1995","digital-markets","transhumanism","research-compilation"],"excerpt":null,"files":[{"path":"1995-extropian-blueprint.pdf","size":14977629}],"content_path":"content/B59-0007"},{"id":"B59-0008","title":"Phil Salin: Architect of Agoric Computing and Digital Liberty","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"writing","description":"Research document on Phil Salin's contributions to agoric computing, digital markets, and the philosophical case for software as protected speech. Covers Salin's work at the American Information Exchange (AMIX), his collaboration with Mark Miller and Eric Drexler, and his 1991 position paper to the U.S. Patent and Trademark Office arguing that computer programs are a form of writing protected by the First Amendment.","citation":"Project B59. (2026, May 24). \"Phil Salin: Architect of Agoric Computing and Digital Liberty.\" Research document generated via Google NotebookLM from collected sources.","provenance":"AI-generated research document produced by Google NotebookLM from sources in the Project B59 research notebook. This is a research compilation, not a primary source document.","hash":"8b0ca937fc2d8d6de37760eb7c4f46fbf2dc4ab882d525d3c2efb89385c05423","tags":["phil-salin","agorics","digital-liberty","free-speech","software-rights","research-compilation"],"excerpt":null,"files":[{"path":"phil-salin-agoric-computing.pdf","size":504544}],"content_path":"content/B59-0008"},{"id":"B59-0009","title":"Computation and Liberty","author":"Project B59 Research / NotebookLM","date":"2026-05-24","type":"writing","description":"Research document exploring the relationship between computational systems and individual liberty. Examines how cryptographic tools, agoric open systems, and decentralized architectures serve as mechanisms for preserving freedom in digital environments, drawing on the work of the Cypherpunks, Extropians, and early digital cash pioneers.","citation":"Project B59. (2026, May 24). \"Computation and Liberty.\" Research document generated via Google NotebookLM from collected sources.","provenance":"AI-generated research document produced by Google NotebookLM from sources in the Project B59 research notebook. This is a research compilation, not a primary source document.","hash":"8aacec58914e713abdd93d4999b1f06d922815fbaa9c0ab1ab0281642fba1ced","tags":["computation","liberty","cryptography","agorics","privacy","research-compilation"],"excerpt":null,"files":[{"path":"computation-and-liberty.pdf","size":1078907}],"content_path":"content/B59-0009"},{"id":"B59-0010","title":"Hal Finney Home Page","author":"Hal Finney","date":"2004-01-01","type":"website","description":"Archived personal homepage of Hal Finney (1956-2014), cryptographer, original PGP 2.0 programmer, creator of RPOW (Reusable Proofs of Work), and the first person to receive a Bitcoin transaction from Satoshi Nakamoto. The page documents his work at PGP Corporation, the RPOW.NET server, the 1995 SSL Challenge, and links to his essays on digital cash, anonymous remailers, steganography, and politics. Finney graduated from Caltech in 1979 with a BS in Engineering.","citation":"Finney, H. (c. 2004). Personal homepage. Originally published at finney.org/~hal/home.html. Archived via fennetic.net/Wayback Machine, captured 24 June 2013.","provenance":"Retrieved from fennetic.net mirror of finney.org via the Wayback Machine, capture dated 24 June 2013. Hal Finney maintained this page from approximately the early 2000s through his ALS diagnosis. Content verified against known biographical details and Finney's published works.","hash":"2e39bf3209bba3f0284441dbbf679fd989d667a833a32df80bdc85ec62227e04","tags":["hal-finney","pgp","rpow","cypherpunks","homepage","primary-source"],"excerpt":null,"files":[{"path":"hal-finney-home-page.html","size":7880,"label":"Read Document","entry":true},{"path":"hal-finney-home-page.html","size":20184,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0010"},{"id":"B59-0011","title":"Politics vs Technology","author":"Hal Finney","date":"1994-01-02","type":"writing","description":"Essay posted to the Cypherpunks Mailing List on January 2, 1994, in which Hal Finney argues that technology alone is insufficient to secure privacy and that political action remains necessary. Responding to the prevailing cypherpunk ethos of \"write code, not laws,\" Finney contends that the Clipper chip proposal, the federal investigation of Phil Zimmermann over PGP, and the difficulty of keeping PGP available on US FTP sites demonstrate that political engagement is indispensable alongside technical work.","citation":"Finney, H. (1994, January 2). \"Politics vs Technology.\" Posted to the Cypherpunks Mailing List (hal@rain.org). Originally published at finney.org/~hal/pol_v_tech.html.","provenance":"Retrieved from finney.org via Wayback Machine capture dated 13 May 2013. Content verified against known Cypherpunks Mailing List archives. The essay is a direct response to discussions on the list regarding the balance between political activism and code-writing as strategies for securing privacy.","hash":"53e17e2b2f70ccf21e56136040c109792d9bb9fc97a1a8a61b4f6e9a18985cba","tags":["hal-finney","cypherpunks","politics","privacy","pgp","clipper-chip","primary-source"],"excerpt":"\"We will have the kind of society that most people want. If we want freedom and privacy, we must persuade others that these are worth having. There are no shortcuts.\"","files":[{"path":"politics-vs-technology.html","size":3692,"label":"Read Document","entry":true},{"path":"politics-vs-technology.html","size":9498,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0011"},{"id":"B59-0012","title":"Freedom of Speech in Software","author":"John Gilmore","date":"1998-10-14","type":"writing","description":"Speech delivered by John Gilmore at ApacheCon on October 14, 1998, arguing that software code is protected expression under the First Amendment. Gilmore traces the history of free speech challenges in software: Phil Salin's July 1991 paper (the first to apply free speech concepts to software), software patent fights, cryptographic export controls, the Bernstein case, PGP, and the EFF's publication of the DES-cracking source code in book form. Warns that if courts allow the government to regulate 'functional' software, Congress could ban any kind of software at will.","citation":"Gilmore, J. (1998, October 14). \"Freedom of Speech in Software.\" Speech delivered at ApacheCon. Published at toad.com/freedom.speech.software.","provenance":"Primary text retrieved from toad.com. MHT archive and plain text version both preserved. Content verified against known accounts of Gilmore's ApacheCon appearance and the legal cases referenced (Bernstein v. Department of State, Phil Zimmermann investigation). Gilmore credits Phil Salin as the originator of the software-as-speech argument.","hash":"e9a8484c6388ccdf099387c2252ca6b283eabdcf64f5d64844d60a834699435e","tags":["john-gilmore","free-speech","software-rights","phil-salin","crypto-wars","bernstein","eff","primary-source"],"excerpt":null,"files":[{"path":"freedom-of-speech-in-software.html","size":27859,"label":"Read Document","entry":true},{"path":"freedom-of-speech-in-software.html","size":69881,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0012"},{"id":"B59-0013","title":"High Tech Hayekians","author":"Don Lavoie, Howard Baetjer, Bill Tulloh, Mark Miller, Eric Drexler, Phil Salin","date":"1990-03-01","type":"writing","description":"Academic paper published in Market Process (Vol. 8, Spring 1990) by the Center for the Study of Market Processes at George Mason University. Documents the Agorics Project, an interdisciplinary exploration of how Friedrich Hayek's economic theories of spontaneous order apply to computer science and software architecture. Describes how Mark Miller and Eric Drexler's work on applying Hayekian principles to computational resource management led to a research collaboration with Austrian economists. Phil Salin is credited with introducing Miller and Drexler to Hayek. The project simulated Mengerian processes for the evolution of money in computational systems.","citation":"Lavoie, D. et al. (1990). \"High Tech Hayekians.\" Market Process, Vol. 8, Spring 1990. Center for the Study of Market Processes, George Mason University. Reprinted from philsalin.com.","provenance":"Retrieved from philsalin.com/hth/hth.html. Slated for reprint in Austrian Perspectives on the New Economy (2001, Routledge). Content verified against known publications from the GMU Center for the Study of Market Processes and the bibliography of the Agorics project.","hash":"759898de1e4b334a0e9a29928e2b26b6f1411b0c64efd9e02c49290a6243b858","tags":["agorics","hayek","austrian-economics","mark-miller","eric-drexler","phil-salin","don-lavoie","smart-contracts","primary-source"],"excerpt":null,"files":[{"path":"high-tech-hayekians.html","size":108624,"label":"Read Document","entry":true},{"path":"high-tech-hayekians.html","size":254141,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0013"},{"id":"B59-0014","title":"Toad Hall -- John Gilmore's Website","author":"John Gilmore","date":"2000-01-01","type":"website","description":"Archived website of Toad Hall, John Gilmore's San Francisco residence that served as a meeting place for early cypherpunks gatherings. Gilmore, co-founder of the Electronic Frontier Foundation and the Cypherpunks Mailing List, maintained toad.com as a hub linking to key documents including Phil Salin's patent office submission on software freedom, Paul Baran's 1964 distributed communications papers, the Gilmore v. Gonzales Supreme Court petition against secret ID requirements for air travel, Linux FreeS/WAN, early Sun User Group tapes (1985-1989), and USENIX newsletters.","citation":"Gilmore, J. (c. 2000s). Toad Hall website. Published at toad.com. Archived as MHT.","provenance":"Retrieved from toad.com. The site served as John Gilmore's personal web presence and a portal to primary documents in cryptography, digital rights, and internet history. Toad Hall (the physical location) hosted early cypherpunks meetings in the San Francisco Bay Area.","hash":"4b933133ffca9498a22a17d3158b0c21c4068140ea67cd227d00730bb2b150e8","tags":["john-gilmore","toad-hall","cypherpunks","eff","website-archive","primary-source"],"excerpt":null,"files":[{"path":"toad-hall.html","size":3567,"label":"Read Document","entry":true},{"path":"toad-hall.html","size":4103,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0014"},{"id":"B59-0015","title":"Release 1.0, Issue 91-11 -- Phil Salin on Opportunity Costs","author":"Esther Dyson (editor), Phil Salin (contributor)","date":"1991-11-25","type":"writing","description":"Issue of Release 1.0, Esther Dyson's influential monthly technology newsletter, dated November 25, 1991. Features Phil Salin's essay \"Costs Are in the Eyes of the Beholders\" on opportunity costs and how information technology changes cost assessment. Salin's bio notes he founded Arc Technologies/StarStruck (the first privately financed rocket launch attempt), worked on the AT&T breakup, and founded the American Information Exchange (AMIX), a subsidiary of Autodesk. The lead article covers Lotus \"Chronicle\" scenario-management features.","citation":"Dyson, E. (Ed.). (1991, November 25). Release 1.0, Issue 91-11. EDventure Holdings. Featuring Salin, P. \"Costs Are in the Eyes of the Beholders.\"","provenance":"PDF scan digitized by Jose Gomez (per PDF metadata). Original publication: Release 1.0, EDventure Holdings, November 1991. Phil Salin's essay appears on pages 4-5. Salin passed away in June 1991; this publication is posthumous, indicating the essay was written earlier.","hash":"00140440cbff203ed1e55c733e74df60701127fbf4e995777e9db9852de83636","tags":["phil-salin","esther-dyson","release-1.0","amix","economics","newsletter","primary-source"],"excerpt":null,"files":[{"path":"release-1.0-nov-1991.pdf","size":1796409,"label":"Read Newsletter (PDF)"}],"content_path":"content/B59-0015"},{"id":"B59-0016","title":"mIRC 7.83 -- IRC Client","author":"Khaled Mardam-Bey","date":"2023-01-01","type":"code","description":"Installer for mIRC version 7.83, the Windows IRC (Internet Relay Chat) client that was ubiquitous in early internet culture. IRC was the primary real-time communication platform for the cypherpunks, open-source developers, hackers, and early cryptocurrency communities throughout the 1990s and 2000s. Preserved as a representative artifact of the communication infrastructure that enabled the cypherpunk movement and early digital culture.","citation":"Mardam-Bey, K. (2023). \"mIRC 7.83.\" Windows IRC client. Published at mirc.com.","provenance":"Installer binary obtained from official distribution. mIRC has been in continuous development since 1995. This version is preserved as a functional artifact representing the communication tools used by the communities documented in The Vault.","hash":"c4e001b16aefb94158c6ee0324491b843639548fe5facbb04a03f45b7e3847a9","tags":["irc","mirc","communication","software","early-internet","tools"],"excerpt":null,"files":[{"path":"mirc783.exe","size":4416368,"label":"Installer (Windows EXE)"}],"content_path":"content/B59-0016"},{"id":"B59-0017","title":"Why Remailers I","author":"Hal Finney","date":"1992-11-15","type":"writing","description":"Essay from November 1992 in which Hal Finney recounts how he discovered David Chaum's cryptographic work and Vernor Vinge's science fiction novella \"True Names,\" explaining why anonymous remailers are an important practical step toward realizing the privacy-preserving technologies those visionaries described. One of the earliest articulations of the practical case for anonymous communication infrastructure on the Cypherpunks Mailing List.","citation":"Finney, H. (1992, November 15). \"Why Remailers I.\" Originally published at finney.org/~hal/why_rem1.html.","provenance":"Retrieved from finney.org via Wayback Machine archive. Content verified against known Cypherpunks Mailing List archives. This is one of Finney's earliest published essays on the list, written within weeks of the group's founding.","hash":"b58b1fb0a2e61a17e23cf57662297d441f8369a9adf3883560e8a4fdea534c86","tags":["hal-finney","remailers","anonymous-communication","david-chaum","vernor-vinge","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"why-remailers-i.html","size":4597,"label":"Read Document","entry":true},{"path":"why-remailers-i.html","size":10378,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0017"},{"id":"B59-0018","title":"Why Remailers II","author":"Hal Finney","date":"1993-02-24","type":"writing","description":"Follow-up essay explaining the practical purposes of anonymous remailers: defeating traffic analysis on email, enabling whistleblowing, and protecting communications privacy beyond what encryption of message content alone provides. Finney argues that even if message contents are encrypted, the metadata of who communicates with whom remains a powerful surveillance tool that remailers are designed to defeat.","citation":"Finney, H. (1993, February 24). \"Why Remailers II.\" Originally published at finney.org/~hal/why_rem2.html.","provenance":"Retrieved from finney.org via Wayback Machine archive. Content verified against known Cypherpunks Mailing List archives.","hash":"672b75c2134b793493a00c07fa57f22b095d178e6a2c0ed881a913b5a5b2e4ae","tags":["hal-finney","remailers","anonymous-communication","traffic-analysis","privacy","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"why-remailers-ii.html","size":5445,"label":"Read Document","entry":true},{"path":"why-remailers-ii.html","size":11228,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0018"},{"id":"B59-0019","title":"Steganography No Solution","author":"Hal Finney","date":"1993-08-12","type":"writing","description":"Essay arguing that steganography and cryptography tools alone will not be sufficient to achieve crypto-anarchy. Finney contends that government opposition and the need for public infrastructure such as digital cash systems cannot be overcome by technology alone -- political action remains necessary. A counterpoint to the prevailing cypherpunk emphasis on code over politics.","citation":"Finney, H. (1993, August 12). \"Steganography No Solution.\" Originally published at finney.org/~hal/steg_no_soln.html.","provenance":"Retrieved from finney.org via Wayback Machine archive. Content verified against known Cypherpunks Mailing List archives.","hash":"a6a3845418307af567ea8e820f1c236a1ee96b7f03ec9b886ea06711d16dfd74","tags":["hal-finney","steganography","crypto-anarchy","politics","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"steganography-no-solution.html","size":3125,"label":"Read Document","entry":true},{"path":"steganography-no-solution.html","size":8952,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0019"},{"id":"B59-0020","title":"Democracy vs. Libertarianism","author":"Hal Finney","date":"1993-08-15","type":"writing","description":"Brief essay in which Finney argues that democracy implicitly recognizes the coercive power of large numbers, and that a populace wise enough to accept a libertarian society would likely be trustworthy enough for democracy anyway. A philosophical exploration of the tension between libertarian ideals and democratic governance that was central to cypherpunk political thought.","citation":"Finney, H. (1993, August 15). \"Democracy vs. Libertarianism.\" Originally published at finney.org/~hal/liberty_demo.html.","provenance":"Retrieved from finney.org via Wayback Machine archive.","hash":"a8237cc5e4c19d4ccf909f412627c6c906f811e36430949b41e7a8beee1e7c59","tags":["hal-finney","democracy","libertarianism","political-philosophy","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"democracy-vs-libertarianism.html","size":1462,"label":"Read Document","entry":true},{"path":"democracy-vs-libertarianism.html","size":7292,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0020"},{"id":"B59-0021","title":"Is-A-Person Credentials","author":"Hal Finney","date":"1993-08-26","type":"writing","description":"Proposes a Chaum-style blind-signature credential system that could verify whether a network identity corresponds to a unique real person without revealing which person, preventing abuse via multiple pseudonyms while preserving anonymity. An early exploration of what would later become known as proof-of-personhood or sybil resistance -- problems still central to digital identity and cryptocurrency systems decades later.","citation":"Finney, H. (1993, August 26). \"Is-A-Person Credentials.\" Originally published at finney.org/~hal/is_a_person.html.","provenance":"Retrieved from finney.org via Wayback Machine archive. The essay applies David Chaum's blind signature protocols to the identity verification problem.","hash":"301285bdedf92605d2ebc4e0cd7697e0293009616b3391a1649cab4f96f0c98f","tags":["hal-finney","digital-identity","blind-signatures","david-chaum","credentials","sybil-resistance","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"is-a-person-credentials.html","size":5560,"label":"Read Document","entry":true},{"path":"is-a-person-credentials.html","size":11376,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0021"},{"id":"B59-0022","title":"Remailer Abuse Prevention","author":"Hal Finney","date":"1994-03-27","type":"writing","description":"Describes a scheme using blind-signature non-abuse tokens built on the Magic Money digital cash software that would allow anonymous remailers to withhold service from users whose messages generate complaints, without compromising sender anonymity. A practical application of digital cash technology to solve the governance problem of anonymous communication systems.","citation":"Finney, H. (1994, March 27). \"Remailer Abuse Prevention.\" Originally published at finney.org/~hal/remailer_abuse.html.","provenance":"Retrieved from finney.org via Wayback Machine archive. References Magic Money, an early digital cash implementation circulated on the Cypherpunks Mailing List.","hash":"54e840066e666337cc4c76a316f5cfe5e2afd6413b8d41df043ca487e70bf01c","tags":["hal-finney","remailers","abuse-prevention","digital-cash","magic-money","blind-signatures","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"remailer-abuse-prevention.html","size":5721,"label":"Read Document","entry":true},{"path":"remailer-abuse-prevention.html","size":11566,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0022"},{"id":"B59-0023","title":"For-Pay Remailers","author":"Hal Finney","date":"1994-10-28","type":"writing","description":"Argues that introducing payment for anonymous remailer services would improve their reliability and sustainability, counteracting the problems inherent in altruism-driven remailers: lack of motivation for operators, vulnerability to spam, and poor quality of service. An early argument for economic sustainability in privacy infrastructure -- the same problem that would later drive the design of incentivized networks like Tor and cryptocurrency mining.","citation":"Finney, H. (1994, October 28). \"For-Pay Remailers.\" Originally published at finney.org/~hal/pay_remail.html.","provenance":"Retrieved from finney.org via Wayback Machine archive.","hash":"7285eaeb69de130100f17a1fe94c105e630cbe6ed15613460270d3d3ccd3f740","tags":["hal-finney","remailers","digital-cash","economics","privacy-infrastructure","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"for-pay-remailers.html","size":12394,"label":"Read Document","entry":true},{"path":"for-pay-remailers.html","size":18211,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0023"},{"id":"B59-0024","title":"David Chaum's Patents on Blind Signatures and Digital Cash","author":"Hal Finney","date":"1995-01-01","type":"writing","description":"Results of Hal Finney's automated patent search on blind-signature-based electronic cash systems, listing patents held by David Chaum and others including Ohta at Nippon Telegraph and Telephone. Compiled as a practical reference for anyone considering implementing digital cash, documenting the patent landscape that constrained development of electronic cash systems in the 1990s.","citation":"Finney, H. (c. 1995). \"Patent Search on Blind Signatures.\" Originally published at finney.org/~hal/chaum_patents.html.","provenance":"Retrieved from finney.org via fennetic.net archive. Date approximate based on content context and Finney's active research period on digital cash implementations.","hash":"d14822b19baf22e357160d877b5fb531409d661618e5e467a3040957302bc341","tags":["hal-finney","david-chaum","patents","blind-signatures","digital-cash","legal","primary-source"],"excerpt":null,"files":[{"path":"chaum-patents.html","size":9177,"label":"Read Document","entry":true},{"path":"chaum-patents.html","size":14969,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0024"},{"id":"B59-0025","title":"Dying Outside","author":"Hal Finney","date":"2009-10-04","type":"writing","description":"Hal Finney's deeply personal essay on LessWrong reflecting on his ALS diagnosis, his progressive symptoms, his decision to pursue cryopreservation with the Alcor Life Extension Foundation, and his philosophical acceptance of mortality. Written through the parable of a man told he has a fatal disease who resolves to live fully anyway. One of the last major writings by the cryptographer who was the first person to receive a Bitcoin transaction and the original programmer of PGP 2.0. Finney passed away on August 28, 2014.","citation":"Finney, H. (2009, October 4). \"Dying Outside.\" Published on LessWrong. Retrieved from lesswrong.com/posts/bshZiaLefDejvPKuS/dying-outside.","provenance":"Retrieved from LessWrong. Published under Finney's own account (halfinney). Content verified against the original LessWrong post URL. Finney was diagnosed with ALS in August 2009 and wrote this essay approximately two months later.","hash":"3f2c80feec864c9ef9f266e1e8bbd329aea36c3fbece9b216846f6c2b3baf0e8","tags":["hal-finney","als","cryonics","mortality","personal","lesswrong","primary-source"],"excerpt":null,"files":[{"path":"dying-outside.html","size":538263,"label":"Read Document","entry":true},{"path":"dying-outside.html","size":982432,"label":"Original MHT Archive (Primary Source)"}],"content_path":"content/B59-0025"},{"id":"B59-0026","title":"Cypherpunks Mailing List Archive -- Searchable by Contributor","author":"Maaria Bajwa (archivist)","date":"1992-01-01","type":"website","description":"Searchable archive of the Cypherpunks Mailing List organized by contributor, containing thousands of messages from key figures in cryptography and digital privacy. The archive indexes 28+ contributors including Timothy C. May (4,104 messages), Perry E. Metzger (2,042), Jim Bell (1,180), Eric Hughes (1,073), Duncan Frissell (991), and others down to single-digit contributions from figures like Bram Cohen and John Perry Barlow. Messages are filterable by label, subject, sender, and date. The Cypherpunks Mailing List was the primary forum where the technical and philosophical foundations of digital cash, anonymous communication, and cryptographic freedom were debated from 1992 onward.","citation":"Bajwa, M. (n.d.). Cypherpunks Mailing List Archive. Published at cypherpunk.maaria.com. Contact: maariabajwa@gmail.com.","provenance":"Live web archive maintained by Maaria Bajwa. Original messages sourced from the Cypherpunks Mailing List (cypherpunks@toad.com and successor lists). This record references the live site; a full local mirror should be created for permanent preservation.","hash":"external-live-site-no-local-copy-yet","tags":["cypherpunks","mailing-list","timothy-may","eric-hughes","perry-metzger","primary-source","external-reference"],"excerpt":null,"files":[],"content_path":null,"external_url":"https://cypherpunk.maaria.com/"},{"id":"B59-0027","title":"Cypherpunks Mailing List Archive -- Cryptoanarchy Wiki","author":"Cryptoanarchy Wiki (maintainers), Ryan Lackey (original archive source)","date":"1992-09-01","type":"website","description":"Complete archive of the Cypherpunks Mailing List from 1992 through early 1999, sourced from Ryan Lackey's cypherpunks.venona.com archive. Each message is indexed with a SHA-256 hash, original headers, and full text. Browsable by date and by author (ranked by frequency or alphabetical). Covers the mailing list's formative years when it was hosted on toad.com before transitioning to distributed architecture. The archive documents discussions on encryption, digital money, anonymous networks, digital pseudonyms, zero knowledge proofs, reputations, and information markets. Archives from 2000-2013 are noted as missing.","citation":"Cryptoanarchy Wiki. (n.d.). Cypherpunks Mailing List Archive. Published at mailing-list-archive.cryptoanarchy.wiki. Source: Ryan Lackey's cypherpunks.venona.com archive. GitHub: cryptoanarchywiki.","provenance":"Community-maintained archive sourced from Ryan Lackey's original mailing list dumps at cypherpunks.venona.com. Each message is individually hashed (SHA-256). Known issues include timezone parsing problems in 1992 data and some orphaned thread replies. Coverage: 1992-1999. Gap: 2000-2013 archives remain unavailable.","hash":"external-live-site-no-local-copy-yet","tags":["cypherpunks","mailing-list","primary-source","ryan-lackey","external-reference","1992-1999"],"excerpt":null,"files":[],"content_path":null,"external_url":"https://mailing-list-archive.cryptoanarchy.wiki/"},{"id":"B59-0028","title":"The Hopping Remailer Is Done -- Eric Hughes","author":"Eric Hughes","date":"1992-09-25","type":"writing","description":"Email from Eric Hughes to the Cypherpunks Mailing List announcing the completion of the first hopping remailer implementation, written in Perl. The system enabled sequential message forwarding through multiple remailers by parsing a 'Request-Remailing-To' header field. Hughes demonstrated the system successfully forwarding a test message through three sequential hops. He acknowledged the system was 'not at all secure by itself' but proposed that combining message body encryption with the hopping mechanism could conceal routing instructions. This is one of the earliest posts on the Cypherpunks Mailing List and documents the first practical implementation of chained anonymous remailing.","citation":"Hughes, E. (1992, September 25). \"the hopping remailer is done.\" Email to cypherpunks@toad.com. From: hughes@soda.berkeley.edu. Message hash: 2fe5a28bc8c23820dc93de1603b58c1ac84c93a16bc852a9b51eb3faed1aa231.","provenance":"Retrieved from mailing-list-archive.cryptoanarchy.wiki, which sources from Ryan Lackey's cypherpunks.venona.com archive. Message authenticated by SHA-256 hash. Original message sent from hughes@soda.berkeley.edu (UC Berkeley) to cypherpunks@toad.com.","hash":"2fe5a28bc8c23820dc93de1603b58c1ac84c93a16bc852a9b51eb3faed1aa231","tags":["eric-hughes","remailers","cypherpunks","mailing-list","perl","anonymous-communication","primary-source"],"excerpt":null,"files":[],"content_path":null,"external_url":"https://mailing-list-archive.cryptoanarchy.wiki/archive/1992/09/2fe5a28bc8c23820dc93de1603b58c1ac84c93a16bc852a9b51eb3faed1aa231/"},{"id":"B59-0029","title":"John Gilmore's Home Page","author":"John Gilmore","date":"1995-01-01","type":"website","description":"Personal homepage of John Gilmore, co-founder of the Electronic Frontier Foundation, co-founder of the Cypherpunks with Eric Hughes and Timothy May, 5th employee at Sun Microsystems, and founder of Cygnus Solutions (sold to Red Hat for $675 million). The page documents his work on encryption export controls, the freedom of movement lawsuit against TSA (Gilmore v. Gonzales), the GNU Radio project, the Free Software movement, criticism of DRM, and his role hosting the original Cypherpunks Mailing List at cypherpunks@toad.com. The live site (toad.com) is currently offline; this record references the Wayback Machine capture.","citation":"Gilmore, J. (c. 1995-2020s). Personal homepage. Originally published at toad.com/gnu/. Wayback Machine capture: web.archive.org/web/20260420104846/http://www.toad.com/gnu/.","provenance":"Original site at toad.com is currently offline (connection refused as of May 2026). Content retrieved from Internet Archive Wayback Machine capture dated April 20, 2026. Gilmore maintained this page for approximately two decades. The site going offline demonstrates exactly the kind of loss The Vault is designed to prevent.","hash":"external-wayback-capture","tags":["john-gilmore","eff","cypherpunks","sun-microsystems","cygnus","free-software","toad-hall","primary-source","external-reference"],"excerpt":null,"files":[],"content_path":null,"external_url":"http://web.archive.org/web/20260420104846/http://www.toad.com/gnu/"},{"id":"B59-0030","title":"Privacy, Technology, and the Open Society","author":"John Gilmore","date":"1991-03-28","type":"writing","description":"Speech delivered by John Gilmore at the First Conference on Computers, Freedom, and Privacy on March 28, 1991. Gilmore argues that the free and open society is being 'nibbled to death by ducks' through small, unheralded changes: the erosion of cash transactions, mandatory identification, mass incarceration, and the danger of census and phone records being used for persecution. He draws parallels to Nazi use of European phone records and Japanese-American internment via census data. Explicitly placed in the public domain by the author. One of the earliest major public speeches connecting cryptographic privacy tools to the defense of civil liberties.","citation":"Gilmore, J. (1991, March 28). \"Privacy, Technology, and the Open Society.\" Speech at the First Conference on Computers, Freedom, and Privacy. Public domain. Originally published at toad.com/gnu/cfp.talk.txt.","provenance":"Original text retrieved from toad.com via Internet Archive Wayback Machine (toad.com currently offline). The speech is explicitly marked as public domain by the author. Delivered at CFP 1991, the first major conference on digital rights, attended by approximately 400 people.","hash":"external-wayback-capture","tags":["john-gilmore","privacy","open-society","cfp-conference","civil-liberties","speech","public-domain","primary-source","external-reference"],"excerpt":null,"files":[],"content_path":null,"external_url":"http://web.archive.org/web/20260417235321/http://www.toad.com/gnu/cfp.talk.txt"},{"id":"B59-0031","title":"DES Review at Stanford University -- NBS/NSA Meeting Transcript, 1976","author":"John Gilmore (transcription), various speakers","date":"1976-01-01","type":"writing","description":"Transcript of the historic 1976 meeting at Stanford University between Stanford computer science researchers, the National Bureau of Standards (NBS), and the National Security Agency (NSA) to discuss the proposed Data Encryption Standard (DES). This meeting was a pivotal moment in the Crypto Wars, where academic cryptographers challenged the government's encryption standard and the NSA's role in weakening it. Background notes by John Gilmore. Transcribed and published to preserve the historical record of government-academic conflict over public cryptographic standards.","citation":"Gilmore, J. (transcriber). (1976/2000s). \"DES Review at Stanford University: A meeting between Stanford computer science researchers, NBS, and NSA, 1976.\" Transcription published at toad.com/des-stanford-meeting.html.","provenance":"Transcript prepared by John Gilmore from recordings of the original 1976 meeting. Published at toad.com. Retrieved from Internet Archive Wayback Machine (toad.com currently offline). The meeting documents the earliest public confrontation between academic cryptographers and US intelligence agencies over encryption standards.","hash":"external-wayback-capture","tags":["des","nsa","nbs","stanford","crypto-wars","encryption-standards","john-gilmore","transcript","1976","primary-source","external-reference"],"excerpt":null,"files":[],"content_path":null,"external_url":"http://web.archive.org/web/20260417033144/http://www.toad.com/des-stanford-meeting.html"},{"id":"B59-0032","title":"Down with Observers!","author":"Hal Finney","date":"1993-08-22","type":"writing","description":"Essay critiquing David Chaum's later turn toward tamper-proof hardware \"observer\" chips for digital cash systems. Finney argues that observer-based protocols compromise the privacy guarantees that made Chaum's earlier blind-signature work so important, trading mathematical certainty for trust in opaque hardware. An early articulation of the principle that cryptographic privacy must be enforced by math, not by hardware secrets.","citation":"Finney, H. (1993, August 22). \"Down with Observers!\" Originally published at finney.org/~hal/anti_observers.html.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"d80e5ddebac316eaa9d72845578dc5714d335a24f858e6a0e8bf2b47d3ce8a5d","tags":["hal-finney","david-chaum","digital-cash","observers","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"down-with-observers.html","size":3948,"label":"Read Essay"}],"content_path":"content/B59-0032"},{"id":"B59-0033","title":"Digital Cash and Privacy","author":"Hal Finney","date":"1993-08-19","type":"writing","description":"Essay on the role of digital cash in protecting privacy as more transactions move online. Finney argues that the financial system's shift toward electronic payments without anonymous cash equivalents would produce unprecedented transaction surveillance, and that systems like Chaum's ecash were necessary to preserve the privacy properties of physical cash in the digital domain.","citation":"Finney, H. (1993, August 19). \"Digital Cash and Privacy.\" Originally published at finney.org/~hal/dig_cash_priv.html.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"8e7f2f16345663812fcc1240ad4b336bb6f7779ca11713a2993ba4229edbb54b","tags":["hal-finney","digital-cash","privacy","ecash","surveillance","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"digital-cash-and-privacy.html","size":6207,"label":"Read Essay"}],"content_path":"content/B59-0033"},{"id":"B59-0034","title":"Chaum's Cash System: Detecting Double-Spending","author":"Hal Finney","date":"1993-10-15","type":"writing","description":"Widely-circulated technical writeup explaining the mathematics behind David Chaum's basic digital cash system, particularly how the protocol allows honest users to remain anonymous while exposing the identity of anyone who attempts to double-spend a digital coin. Finney's clearest exposition of the cut-and-choose blind signature protocol that made anonymous-but-accountable digital cash possible.","citation":"Finney, H. (1993, October 15). \"Detecting Double-Spending.\" Originally published at finney.org/~hal/chcash2.html. Widely republished on the net.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"40c3932e4bac1728e8c423d97c4d26731ededb913335cb070af1ad33176d74e4","tags":["hal-finney","david-chaum","digital-cash","double-spending","blind-signatures","cryptography","primary-source"],"excerpt":null,"files":[{"path":"chaums-cash-system-detecting-double-spending.html","size":15448,"label":"Read Essay"}],"content_path":"content/B59-0034"},{"id":"B59-0035","title":"NetCash: First Reaction","author":"Hal Finney","date":"1993-08-17","type":"writing","description":"Finney's initial critical analysis of NetCash, an early digital payment proposal. The essay examines the trade-offs between centralized and decentralized digital payment architectures and identifies weaknesses in systems that depended on trusted intermediaries rather than cryptographic guarantees.","citation":"Finney, H. (1993, August 17). \"NetCash (First Reaction).\" Originally published at finney.org/~hal/netcash_crit.html.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"7bf722559bf632446c85d4599297c16145dc104f9dbe0316ca979e10c07623da","tags":["hal-finney","netcash","digital-cash","critique","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"netcash-first-reaction.html","size":2233,"label":"Read Essay"}],"content_path":"content/B59-0035"},{"id":"B59-0036","title":"PGP Math Library Documentation","author":"Hal Finney","date":"1993-11-26","type":"writing","description":"Technical documentation by Finney explaining the inner workings of the mathematical functions in PGP's math library. As one of the original PGP 2.0 programmers working directly with Phil Zimmermann, Finney provides authoritative insight into the multi-precision arithmetic, modular exponentiation, and prime number operations that made PGP's RSA implementation work on the hardware of the early 1990s.","citation":"Finney, H. (1993, November 26). \"PGP Math Library.\" Originally published at finney.org/~hal/pgp_math_lib.html.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"32260c1e38afba315bcb242b9b76b14039e0df70e0534223ec5d00cb1bad5718","tags":["hal-finney","pgp","cryptography","mathematics","rsa","documentation","primary-source"],"excerpt":null,"files":[{"path":"pgp-math-library.html","size":13255,"label":"Read Essay"}],"content_path":"content/B59-0036"},{"id":"B59-0037","title":"Truly Stealthy PGP","author":"Hal Finney","date":"1994-03-06","type":"writing","description":"Analysis of what would be required to make PGP-encrypted messages indistinguishable from random data. Finney examines the limitations of \"Stealth PGP\" variants and discusses how the structure of PGP packets makes encrypted messages identifiable as PGP traffic. Relevant to traffic analysis resistance and steganographic uses of encryption.","citation":"Finney, H. (1994, March 6). \"Truly Stealthy PGP.\" Originally published at finney.org/~hal/stealth_pgp.html.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"d1db80c4103a12efad56fef305c4affaaabe5207bdebc341f83bce05a98fff85","tags":["hal-finney","pgp","steganography","stealth","traffic-analysis","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"truly-stealthy-pgp.html","size":2940,"label":"Read Essay"}],"content_path":"content/B59-0037"},{"id":"B59-0038","title":"The Beauty of ECash","author":"Hal Finney","date":"1994-03-16","type":"writing","description":"Finney's appreciation of the elegance of David Chaum's ecash protocol. The essay explains why the cryptographic design of ecash represents a particularly elegant solution to the problem of creating digital cash that is simultaneously anonymous, verifiable, and resistant to double-spending. A clear statement of why Chaum's blind signature approach was, to Finney, the right approach.","citation":"Finney, H. (1994, March 16). \"The Beauty of ECash.\" Originally published at finney.org/~hal/beauty_ecash.html.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"9b33cf342c27366ba5e2454c80e5b054c075d8fe45fe4d3e93aeb98254d2e80e","tags":["hal-finney","ecash","david-chaum","digital-cash","blind-signatures","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"the-beauty-of-ecash.html","size":5683,"label":"Read Essay"}],"content_path":"content/B59-0038"},{"id":"B59-0039","title":"PGP Web of Trust Misconceptions","author":"Hal Finney","date":"1994-03-30","type":"writing","description":"Essay addressing common misconceptions about PGP's web of trust model. Finney examines whether the decentralized trust architecture that worked for the early cypherpunk community could scale to global usage, and what would be required for the model to remain useful as the user base grew beyond people who could meet in person at key-signing parties.","citation":"Finney, H. (1994, March 30). \"PGP Web of Trust Misconceptions.\" Originally published at finney.org/~hal/web_of_trust.html.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"d3dadbba97af4edeca1d92600278ebf1c9b8c4616de5c76289bbba28da2efc8a","tags":["hal-finney","pgp","web-of-trust","trust-models","cryptography","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"pgp-web-of-trust-misconceptions.html","size":5472,"label":"Read Essay"}],"content_path":"content/B59-0039"},{"id":"B59-0040","title":"The SSL Challenge","author":"Hal Finney","date":"1995-08-01","type":"writing","description":"In August 1995 Hal Finney issued a public challenge to the cryptographic community: break a sample web browsing session run in secure mode using Netscape's Secure Socket Layer (SSL) protocol with the export-grade 40-bit encryption then mandated by US regulations. The challenge was broken in short order, demonstrating that export-controlled encryption was inadequate for any serious commercial use and contributing to the eventual relaxation of US encryption export controls.","citation":"Finney, H. (1995, August). \"The SSL Challenge.\" Originally published at finney.org/~hal/sslchal.html.","provenance":"Retrieved from finney.org/~hal/ via the Internet Archive Wayback Machine. finney.org is currently inaccessible; this archive preserves the essay as it appeared on Hal Finney's personal homepage. Original publication date as indicated in the document text.","hash":"c77fcb51fa2d5c64022d18f7ec86ddeeaea32d6af453aad020a4390cb2260b3a","tags":["hal-finney","ssl","netscape","crypto-wars","export-controls","challenge","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"the-ssl-challenge.html","size":12449,"label":"Read Essay"}],"content_path":"content/B59-0040"},{"id":"B59-0041","title":"Hal Finney: Digital Architect","author":"Project B59 Research / NotebookLM","date":"2026-05-25","type":"video","description":"Long-form video overview (9 minutes) profiling Hal Finney as a foundational architect of digital privacy and electronic cash systems. Covers Finney's role as the original PGP 2.0 programmer working directly with Phil Zimmermann, his work on the RPOW (Reusable Proofs of Work) system that prefigured Bitcoin's mining mechanism, his receipt of the first Bitcoin transaction from Satoshi Nakamoto, and his philosophical writings on remailers, privacy, and the technical underpinnings of crypto-anarchy.","citation":"Project B59. (2026, May 25). \"Hal Finney: Digital Architect.\" Long-form video overview generated via Google NotebookLM from collected primary sources including Finney's essays preserved in The Vault.","provenance":"AI-generated video overview produced by Google NotebookLM from sources in the Project B59 research notebook, including the Hal Finney essay collection (B59-0010, B59-0017 through B59-0025, B59-0032 through B59-0040) preserved in The Vault. This is a research compilation, not primary source footage.","hash":"9a2673dba41edac16d5beb744dbb49c996a1c47f75af5975b9a105d862ecc71e","tags":["hal-finney","pgp","rpow","bitcoin","satoshi","cypherpunks","video-overview","research-compilation"],"excerpt":null,"files":[{"path":"hal-finney-digital-architect.mp4","size":48659967,"label":"Watch Overview (9 min)","entry":true}],"content_path":"content/B59-0041"},{"id":"B59-0042","title":"Cypherpunk Research Repository (Tom Busby, 2018)","author":"Tom Busby","date":"2018-05-26","type":"code","description":"Curated GitHub repository compiled by Tom Busby (Twitter: @_tombusby) cataloging the cypherpunk movement: 40+ individual person profiles (Adam Back, Wei Dai, Julian Assange, David Chaum, Hal Finney, Satoshi Nakamoto, Cody Wilson, Ross Ulbricht, Phil Zimmermann, and many more), notable events (Silk Road, Mt.Gox, DAO Hack, Snowden leaks, 90s Crypto Wars), organizations (EFF, Paralelni Polis), and project documentation. Each entry is a structured Markdown file with biographical info, key contributions, and links to primary sources. The repository includes references to the Cypherpunks Mailing List Archives (1992-1998) and the Cyphernomicon FAQ. Designed as a research backbone for articles and book-length work on cypherpunk history.","citation":"Busby, T. (2018, May 26). \"cypherpunk-research.\" GitHub repository. Commit hash: be387755363b0d8c5bd38aabec8385f449a262ef. Compiled to support future articles and a planned book on cypherpunk history.","provenance":"Cloned from GitHub at commit be387755363b0d8c5bd38aabec8385f449a262ef, dated 26 May 2018. Repository structure intact: README.md, /people/ (40+ profiles), /events/, /organisations/, /images/, /unsorted.md, and contribution guidelines. Preserved as a downloadable ZIP archive plus an inline HTML rendering of the README for browsing.","hash":"ead23ca14a82a12007bfe36d4aaf2663a6650ec0fd2b494efd51e221b49c0938","tags":["cypherpunks","research-compilation","github","tom-busby","reference","external-research","mailing-list"],"excerpt":null,"files":[{"path":"cypherpunk-research-readme.html","size":53564,"label":"Browse Repository README","entry":true},{"path":"cypherpunk-research-2018.zip","size":132537,"label":"Download Full Repository (ZIP)"}],"content_path":"content/B59-0042"},{"id":"B59-0043","title":"Smart Contracts","author":"Nick Szabo","date":"1994-01-01","type":"writing","description":"Nick Szabo's foundational essay introducing the concept of \"smart contracts\" - self-executing computerized transaction protocols that enforce contractual clauses. Coined the term that has shaped decades of digital agreement design.","citation":"Szabo, N. (1994). \"Smart Contracts.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/smart-contracts/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/smart-contracts/","hash":"20f5a279593ee74d748d080b64b646ce9f75733920d870abf6453eb3ad7ff5da","tags":["nick-szabo","cypherpunks","primary-source","smart-contracts"],"excerpt":null,"files":[{"path":"smart-contracts.html","size":63555,"label":"Read Essay","entry":true}],"content_path":"content/B59-0043"},{"id":"B59-0044","title":"The Idea of Smart Contracts","author":"Nick Szabo","date":"1997-01-01","type":"writing","description":"Szabo's elaboration of the smart contract concept, examining how cryptographic protocols and digital security mechanisms could embed contractual obligations directly into hardware and software. Argues for minimizing the need for trusted intermediaries through automated enforcement.","citation":"Szabo, N. (1997). \"The Idea of Smart Contracts.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/the-idea-of-smart-contracts/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/the-idea-of-smart-contracts/","hash":"8fad07a3476eca7dc17b97054067146d072cb01c59b10c7b55be82306fd679ff","tags":["nick-szabo","cypherpunks","primary-source","smart-contracts","trust"],"excerpt":null,"files":[{"path":"the-idea-of-smart-contracts.html","size":53416,"label":"Read Essay","entry":true}],"content_path":"content/B59-0044"},{"id":"B59-0045","title":"Formalizing and Securing Relationships on Public Networks","author":"Nick Szabo","date":"1997-09-01","type":"writing","description":"Published in First Monday (Vol. 2, No. 9). A comprehensive paper on the application of cryptographic and contract-theoretic principles to relationships on public networks. Outlines the conceptual framework that smart contracts and digital agreements would later build upon.","citation":"Szabo, N. (1997). \"Formalizing and Securing Relationships on Public Networks.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/formalizing-securing-relationships/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/formalizing-securing-relationships/","hash":"3b58976fbb24e0546daa65b81e80777615c49aca6437492b44b9f940c7604a10","tags":["nick-szabo","cypherpunks","primary-source","smart-contracts"],"excerpt":null,"files":[{"path":"formalizing-securing-relationships.html","size":242128,"label":"Read Essay","entry":true}],"content_path":"content/B59-0045"},{"id":"B59-0046","title":"Bit Gold","author":"Nick Szabo","date":"2005-12-29","type":"writing","description":"The seminal proposal for Bit Gold - a digital currency system using proof-of-work to create unforgeable scarce digital tokens. Originally circulated on the libtech mailing list in 1998 and published on the Unenumerated blog in 2005. A direct conceptual precursor to Bitcoin's design.","citation":"Szabo, N. (2005). \"Bit Gold.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/bit-gold/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/bit-gold/","hash":"6e540747c324bb62039abdaf85bf8e788bb4cbdf1bd74fbf820adfb033e94673","tags":["nick-szabo","cypherpunks","primary-source","cryptography","bit-gold","bitcoin"],"excerpt":null,"files":[{"path":"bit-gold.html","size":57958,"label":"Read Essay","entry":true}],"content_path":"content/B59-0046"},{"id":"B59-0047","title":"Bit Gold Markets","author":"Nick Szabo","date":"2008-01-01","type":"writing","description":"Follow-up writing on the market design for Bit Gold, examining how the proof-of-work tokens would establish value and circulate. Refinements to the original Bit Gold proposal addressing market dynamics.","citation":"Szabo, N. (2008). \"Bit Gold Markets.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/bit-gold-markets/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/bit-gold-markets/","hash":"8326df260f871c56d313a1ede64b7b0b37b42de6f5a4d37ea77e530c3d1bf01a","tags":["nick-szabo","cypherpunks","primary-source","cryptography","bit-gold"],"excerpt":null,"files":[{"path":"bit-gold-markets.html","size":60759,"label":"Read Essay","entry":true}],"content_path":"content/B59-0047"},{"id":"B59-0048","title":"Shelling Out: The Origins of Money","author":"Nick Szabo","date":"2002-01-01","type":"writing","description":"Szabo's influential anthropological essay on the origins of money, drawing on game theory, evolutionary psychology, and the concept of focal points (Schelling points). Argues that money emerged from collectible objects valued for non-monetary reasons before becoming media of exchange.","citation":"Szabo, N. (2002). \"Shelling Out: The Origins of Money.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/shelling-out/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/shelling-out/","hash":"99ac9c41c3e774faeb51cc230a50fcdfda1baa6a49e16d713520b033306ed12d","tags":["nick-szabo","cypherpunks","primary-source","cryptography","digital-money"],"excerpt":null,"files":[{"path":"shelling-out.html","size":252363,"label":"Read Essay","entry":true}],"content_path":"content/B59-0048"},{"id":"B59-0049","title":"Trusted Third Parties Are Security Holes","author":"Nick Szabo","date":"2001-01-01","type":"writing","description":"Foundational essay arguing that trusted third parties represent security vulnerabilities in computer protocols. Has become a touchstone reference in cryptography and decentralized system design - the principle behind why blockchain systems minimize trust requirements.","citation":"Szabo, N. (2001). \"Trusted Third Parties Are Security Holes.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/trusted-third-parties/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/trusted-third-parties/","hash":"d0c29beca1f9a51984633f476265a7cb55e34308099a6a9fa1482f235e7af5c8","tags":["nick-szabo","cypherpunks","primary-source","cryptography","blockchain","trust"],"excerpt":null,"files":[{"path":"trusted-third-parties.html","size":107846,"label":"Read Essay","entry":true}],"content_path":"content/B59-0049"},{"id":"B59-0050","title":"The God Protocols","author":"Nick Szabo","date":"1999-01-01","type":"writing","description":"Published in ITAudit (Vol. 2). Szabo's vision of \"God protocols\" - hypothetical cryptographic protocols that would perform computations with absolute trustworthiness, preserving input confidentiality while producing verifiable outputs. A theoretical target for multiparty secure computation.","citation":"Szabo, N. (1999). \"The God Protocols.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/the-god-protocols/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/the-god-protocols/","hash":"129566b6940bfe87057fdfe5e480f7c03d5ebdadcea3a392a9c440dca55562e8","tags":["nick-szabo","cypherpunks","primary-source","cryptography","trust","auditing"],"excerpt":null,"files":[{"path":"the-god-protocols.html","size":68347,"label":"Read Essay","entry":true}],"content_path":"content/B59-0050"},{"id":"B59-0051","title":"Secure Property Titles with Owner Authority","author":"Nick Szabo","date":"1998-01-01","type":"writing","description":"Proposal for cryptographically secured property title systems that would allow owners to assert claims without relying on centralized registries. Foundational to thinking about decentralized ownership records and what would become NFT and tokenization concepts.","citation":"Szabo, N. (1998). \"Secure Property Titles with Owner Authority.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/secure-property-titles/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/secure-property-titles/","hash":"68b65911e238079f65df15a25c9db72b8bbb20da5f79c1df2a1e6011e4c0dc40","tags":["nick-szabo","cypherpunks","primary-source","cryptography","digital-property"],"excerpt":null,"files":[{"path":"secure-property-titles.html","size":88620,"label":"Read Essay","entry":true}],"content_path":"content/B59-0051"},{"id":"B59-0052","title":"Bitcoin, What Took Ye So Long?","author":"Nick Szabo","date":"2011-05-28","type":"writing","description":"Szabo's 2011 retrospective on the development of Bitcoin and the decades of research that preceded it. Examines why digital currency took so long to be realized despite all the prior theoretical work.","citation":"Szabo, N. (2011). \"Bitcoin, What Took Ye So Long?.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/bitcoin-what-took-ye-so-long/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/bitcoin-what-took-ye-so-long/","hash":"6d3f50a9d817f6bfafe58df847b812a7be203fa813e8e9f9abe30b5e2ef1f807","tags":["nick-szabo","cypherpunks","primary-source","cryptography","bitcoin"],"excerpt":null,"files":[{"path":"bitcoin-what-took-ye-so-long.html","size":55076,"label":"Read Essay","entry":true}],"content_path":"content/B59-0052"},{"id":"B59-0053","title":"Money, Blockchains, and Social Scalability","author":"Nick Szabo","date":"2017-02-09","type":"writing","description":"Szabo's influential 2017 essay introducing the concept of \"social scalability\" - the ability of institutions to scale up the number of participants who can mutually benefit despite limited trust. Argues that blockchains achieve social scalability by reducing trust requirements.","citation":"Szabo, N. (2017). \"Money, Blockchains, and Social Scalability.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/money-blockchains-and-social-scalability/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/money-blockchains-and-social-scalability/","hash":"a52c9712980efd9fa1cfa47c153bff4563c3d438a58babb83380fe40f6d93380","tags":["nick-szabo","cypherpunks","primary-source","cryptography","digital-money","blockchain","trust","scalability"],"excerpt":null,"files":[{"path":"money-blockchains-social-scalability.html","size":151277,"label":"Read Essay","entry":true}],"content_path":"content/B59-0053"},{"id":"B59-0054","title":"Micropayments and Mental Transaction Costs","author":"Nick Szabo","date":"1999-05-01","type":"writing","description":"Presented at the 2nd Berlin Internet Economics Workshop, May 1999. Argues that the failure of micropayment systems is due not just to technical barriers but to the cognitive burden of evaluating many small transactions - the \"mental transaction cost\" barrier.","citation":"Szabo, N. (1999). \"Micropayments and Mental Transaction Costs.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/micropayments-and-mental-transaction-costs/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/micropayments-and-mental-transaction-costs/","hash":"b13386ce2723fcaac12ff56906866a389ed28a451ce24bfba617044929f40d0c","tags":["nick-szabo","cypherpunks","primary-source","cryptography","micropayments"],"excerpt":null,"files":[{"path":"micropayments-mental-transaction-costs.html","size":141766,"label":"Read Essay","entry":true}],"content_path":"content/B59-0054"},{"id":"B59-0055","title":"Advances in Distributed Security","author":"Nick Szabo","date":"2003-01-01","type":"writing","description":"Szabo's overview of advances in distributed security architectures, surveying techniques for building secure systems without centralized trust points. Covers practical applications of the principles in \"Trusted Third Parties Are Security Holes.\"","citation":"Szabo, N. (2003). \"Advances in Distributed Security.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/advances-in-distributed-security/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/advances-in-distributed-security/","hash":"20f7f97803ced637e769c837c8c2e51b7034fa977f48330250e312ebe00e7e86","tags":["nick-szabo","cypherpunks","primary-source","cryptography","trust"],"excerpt":null,"files":[{"path":"advances-distributed-security.html","size":193097,"label":"Read Essay","entry":true}],"content_path":"content/B59-0055"},{"id":"B59-0056","title":"Contracts with Bearer","author":"Nick Szabo","date":"2002-01-01","type":"writing","description":"Examines digital bearer contracts - cryptographic instruments where possession of a token grants the holder specific rights. Foundational to thinking about cryptographic property rights and the architecture of digital cash and stablecoins.","citation":"Szabo, N. (2002). \"Contracts with Bearer.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/contracts-with-bearer/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/contracts-with-bearer/","hash":"6e18f8173faf4196165d46d3a99dfdd5a8bdfee9ff8259e74837077790b2b8e9","tags":["nick-szabo","cypherpunks","primary-source","smart-contracts","digital-property"],"excerpt":null,"files":[{"path":"contracts-with-bearer.html","size":89770,"label":"Read Essay","entry":true}],"content_path":"content/B59-0056"},{"id":"B59-0057","title":"Rights, Remedies, and Security Models","author":"Nick Szabo","date":"2004-01-01","type":"writing","description":"Szabo's exploration of the relationship between legal rights, available remedies, and the security models that protocols enforce. Bridges legal theory and cryptographic protocol design.","citation":"Szabo, N. (2004). \"Rights, Remedies, and Security Models.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/rights-remedies-and-security-models/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/rights-remedies-and-security-models/","hash":"cb90b1df645619daaedb2738f7f612ad3d50c3b2c91566701e6b4b01b9b8591b","tags":["nick-szabo","cypherpunks","primary-source","cryptography"],"excerpt":null,"files":[{"path":"rights-remedies-security-models.html","size":69918,"label":"Read Essay","entry":true}],"content_path":"content/B59-0057"},{"id":"B59-0058","title":"An Introduction to Algorithmic Information Theory","author":"Nick Szabo","date":"2000-01-01","type":"writing","description":"Szabo's accessible introduction to algorithmic information theory - the mathematics of randomness, complexity, and compression. Important foundation for understanding the information-theoretic properties of cryptographic systems.","citation":"Szabo, N. (2000). \"An Introduction to Algorithmic Information Theory.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/introduction-to-algorithmic-information-theory/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/introduction-to-algorithmic-information-theory/","hash":"6f15f9f9469f809a589d41eadb2ebf9a5f90e4fbb76ed995f62f13f601ff2414","tags":["nick-szabo","cypherpunks","primary-source","cryptography"],"excerpt":null,"files":[{"path":"introduction-algorithmic-info-theory.html","size":75232,"label":"Read Essay","entry":true}],"content_path":"content/B59-0058"},{"id":"B59-0059","title":"Confidential Auditing","author":"Nick Szabo","date":"2002-01-01","type":"writing","description":"Proposal for cryptographic protocols that allow auditing of accounts and transactions while preserving the confidentiality of underlying data. Addresses the tension between transparency and privacy in financial systems.","citation":"Szabo, N. (2002). \"Confidential Auditing.\" Retrieved from Nakamoto Institute Library (https://nakamotoinstitute.org/library/confidential-auditing/).","provenance":"Retrieved from the Satoshi Nakamoto Institute Library, which preserves Szabo's writings from his original (now defunct) szabo.best.vwh.net site and related publications. Original URL: https://nakamotoinstitute.org/library/confidential-auditing/","hash":"fefa53b8afd7ec595b974a58179d7c77adda9148e4459cf1ac95a3e81c04e83d","tags":["nick-szabo","cypherpunks","primary-source","cryptography","auditing"],"excerpt":null,"files":[{"path":"confidential-auditing.html","size":57072,"label":"Read Essay","entry":true}],"content_path":"content/B59-0059"},{"id":"B59-0060","title":"Hermeneutics","author":"Nick Szabo","date":"1997-01-01","type":"writing","description":"Szabo's exploration of hermeneutics - the theory of interpretation - applied to legal and computational systems. Examines how the meanings of contracts, code, and rules are constructed through interpretation rather than read off mechanically.","citation":"Szabo, N. (1997). \"Hermeneutics.\" Retrieved from https://szabo.best.vwh.net/hermeneutics.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/hermeneutics.html","hash":"24ee3776ecf495fff478e3d8c86d7b2f2bf6063ceadc77d13afc81d022b94b78","tags":["nick-szabo","cypherpunks","primary-source","legal-theory"],"excerpt":null,"files":[{"path":"hermeneutics.html","size":23750,"label":"Read Essay","entry":true}],"content_path":"content/B59-0060"},{"id":"B59-0061","title":"A Formal Language for Analyzing Contracts","author":"Nick Szabo","date":"2002-01-01","type":"writing","description":"Szabo's proposal for a formal language to represent and analyze contracts. Develops the theoretical foundation for representing contractual obligations in a way that can be mechanically processed - prefiguring the smart contract languages that would emerge with blockchain platforms.","citation":"Szabo, N. (2002). \"A Formal Language for Analyzing Contracts.\" Retrieved from https://szabo.best.vwh.net/contractlanguage.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/contractlanguage.html","hash":"41622787a3985aeec1df7cb51d98292dcd58ad8f3bc3b9332e675527cd389d9c","tags":["nick-szabo","cypherpunks","primary-source","smart-contracts"],"excerpt":null,"files":[{"path":"formal-language-contracts.html","size":68141,"label":"Read Essay","entry":true}],"content_path":"content/B59-0061"},{"id":"B59-0062","title":"Patterns of Integrity: Separation of Duties","author":"Nick Szabo","date":"1998-01-01","type":"writing","description":"Examines the principle of separation of duties as a fundamental security pattern. Argues that the same principle that prevents fraud in accounting practices applies broadly to computer system design and cryptographic protocols.","citation":"Szabo, N. (1998). \"Patterns of Integrity: Separation of Duties.\" Retrieved from https://szabo.best.vwh.net/separationofduties.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/separationofduties.html","hash":"c4f6f4821a06628abf4202227bd8b13dd81824648fe872615546fe45301c5109","tags":["nick-szabo","cypherpunks","primary-source","cryptography"],"excerpt":null,"files":[{"path":"separation-of-duties.html","size":11660,"label":"Read Essay","entry":true}],"content_path":"content/B59-0062"},{"id":"B59-0063","title":"Intrapolynomial Cryptography","author":"Nick Szabo","date":"2003-01-01","type":"writing","description":"Szabo's exploration of cryptographic constructions based on intrapolynomial functions. Technical paper on alternative mathematical foundations for cryptographic primitives.","citation":"Szabo, N. (2003). \"Intrapolynomial Cryptography.\" Retrieved from https://szabo.best.vwh.net/intrapoly.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/intrapoly.html","hash":"a3df64381edda745d25a44f43ac13c33aeae037c6372f8d7c6becc16e76c4f04","tags":["nick-szabo","cypherpunks","primary-source","cryptography"],"excerpt":null,"files":[{"path":"intrapolynomial-cryptography.html","size":4076,"label":"Read Essay","entry":true}],"content_path":"content/B59-0063"},{"id":"B59-0064","title":"There Is No Universal Security Architecture","author":"Nick Szabo","date":"2003-01-01","type":"writing","description":"Argues against the notion of a single universal security architecture that could solve all security problems. Different threat models, environments, and adversaries require different security architectures - one size cannot fit all.","citation":"Szabo, N. (2003). \"There Is No Universal Security Architecture.\" Retrieved from https://szabo.best.vwh.net/universal.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/universal.html","hash":"f5a1b2e71bd17961af3847c0db97837f2b1bf54922757d4c26a55802648ad98e","tags":["nick-szabo","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"no-universal-security.html","size":3858,"label":"Read Essay","entry":true}],"content_path":"content/B59-0064"},{"id":"B59-0065","title":"Distributing Authorities and Verifying Their Claims","author":"Nick Szabo","date":"2003-01-01","type":"writing","description":"Examines how authority can be distributed across multiple parties and how verifying their claims requires careful protocol design. Foundational to thinking about decentralized governance and federated identity systems.","citation":"Szabo, N. (2003). \"Distributing Authorities and Verifying Their Claims.\" Retrieved from https://szabo.best.vwh.net/authorities.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/authorities.html","hash":"47a54450760508b80d855e506d84fdad9f0022ad7506a83a45e9463cb811977c","tags":["nick-szabo","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"distributing-authorities.html","size":9580,"label":"Read Essay","entry":true}],"content_path":"content/B59-0065"},{"id":"B59-0066","title":"Coalition Design for Secure Protocols","author":"Nick Szabo","date":"2003-01-01","type":"writing","description":"Analyzes how secure protocols should be designed to remain secure even when subsets of participants form coalitions to attack the protocol. Game-theoretic approach to cryptographic protocol design.","citation":"Szabo, N. (2003). \"Coalition Design for Secure Protocols.\" Retrieved from https://szabo.best.vwh.net/coalition.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/coalition.html","hash":"d1bd146301e87ece46249b87270883268c930ba02c88b234a59636ca9dfaa1bd","tags":["nick-szabo","cypherpunks","primary-source","cryptography"],"excerpt":null,"files":[{"path":"coalition-design.html","size":6881,"label":"Read Essay","entry":true}],"content_path":"content/B59-0066"},{"id":"B59-0067","title":"Measuring Value","author":"Nick Szabo","date":"2002-01-01","type":"writing","description":"Szabo's essay on the philosophical and economic foundations of measuring value. Explores why value cannot be measured the way physical quantities can be, and what this means for monetary and contractual systems.","citation":"Szabo, N. (2002). \"Measuring Value.\" Retrieved from https://szabo.best.vwh.net/measuringvalue.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/measuringvalue.html","hash":"d235ff1b799e15800db43946f78a21e094c22752d36f874e31b6eadcfcac07f5","tags":["nick-szabo","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"measuring-value.html","size":39474,"label":"Read Essay","entry":true}],"content_path":"content/B59-0067"},{"id":"B59-0068","title":"Brehon Law","author":"Nick Szabo","date":"2003-01-01","type":"writing","description":"Examines Brehon Law - the early Irish legal system that operated through reputation, surety, and decentralized enforcement before the imposition of centralized Norman law. A historical case study in legal systems that functioned without a strong central authority.","citation":"Szabo, N. (2003). \"Brehon Law.\" Retrieved from https://szabo.best.vwh.net/brehon.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/brehon.html","hash":"2f346b64b5aced2893b012ed5b34a0f3cf5c7e5e83cf4c19ff68b33a042ad4ff","tags":["nick-szabo","cypherpunks","primary-source","legal-theory"],"excerpt":null,"files":[{"path":"brehon-law.html","size":4381,"label":"Read Essay","entry":true}],"content_path":"content/B59-0068"},{"id":"B59-0069","title":"Recovering Privity","author":"Nick Szabo","date":"2003-01-01","type":"writing","description":"Szabo's argument for restoring the legal doctrine of privity of contract - the principle that contracts bind only the parties to them. Examines how this doctrine has eroded and the implications for digital agreements and decentralized commerce.","citation":"Szabo, N. (2003). \"Recovering Privity.\" Retrieved from https://szabo.best.vwh.net/privity.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/privity.html","hash":"b8a0eb87cee322fcefe22975aebcc5a8a519cd4478d5e28b7d9377c8de95e8e0","tags":["nick-szabo","cypherpunks","primary-source","legal-theory"],"excerpt":null,"files":[{"path":"recovering-privity.html","size":10192,"label":"Read Essay","entry":true}],"content_path":"content/B59-0069"},{"id":"B59-0070","title":"Video Contracts","author":"Nick Szabo","date":"1998-01-01","type":"writing","description":"Proposal for using video technology to create more robust and verifiable contracts. An early exploration of how multimedia could enhance the security and clarity of contractual agreements.","citation":"Szabo, N. (1998). \"Video Contracts.\" Retrieved from https://szabo.best.vwh.net/video.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/video.html","hash":"620a9606ab7b556a59a29f7f18f3dcc26caa13070acb369aab2e214ef6c8128d","tags":["nick-szabo","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"video-contracts.html","size":11600,"label":"Read Essay","entry":true}],"content_path":"content/B59-0070"},{"id":"B59-0071","title":"Trusted Services and Group Controls","author":"Nick Szabo","date":"1998-01-01","type":"writing","description":"Examines the design of trusted services and the controls that groups can impose on their members and operations. Foundational thinking about institutional design in digital contexts.","citation":"Szabo, N. (1998). \"Trusted Services and Group Controls.\" Retrieved from https://szabo.best.vwh.net/groupcontrols.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/groupcontrols.html","hash":"fd66c2dcf3e03c1083bf410629df97a80e59fccc34c0d2c4e334e9e8a856f6ae","tags":["nick-szabo","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"group-controls.html","size":8521,"label":"Read Essay","entry":true}],"content_path":"content/B59-0071"},{"id":"B59-0072","title":"Online Communities: From the Usenet FAQ","author":"Nick Szabo","date":"1998-01-01","type":"writing","description":"Szabo's analysis of online communities drawing on the Usenet FAQ and the patterns of self-governance that emerged in early Internet forums. Relevant to understanding decentralized community moderation.","citation":"Szabo, N. (1998). \"Online Communities: From the Usenet FAQ.\" Retrieved from https://szabo.best.vwh.net/usenet.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/usenet.html","hash":"8ef83a933c22fc9fdbf3018902f8e583738b31e499e9247bf6d7d74559903ffe","tags":["nick-szabo","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"usenet-faq.html","size":4804,"label":"Read Essay","entry":true}],"content_path":"content/B59-0072"},{"id":"B59-0073","title":"Proplets","author":"Nick Szabo","date":"1998-01-01","type":"writing","description":"Szabo's concept of \"proplets\" - small property tokens that could be used in digital commerce. Architecture for securing and transferring physical and digital property using cryptographic credentials. A precursor to tokenization and NFT concepts.","citation":"Szabo, N. (1998). \"Proplets.\" Retrieved from https://szabo.best.vwh.net/proplets.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/proplets.html","hash":"21331cafd30098077679e01478731bce8bdb99e8b4b6b6c33ec1d516d847e37d","tags":["nick-szabo","cypherpunks","primary-source","digital-property","cryptography"],"excerpt":null,"files":[{"path":"proplets.html","size":9874,"label":"Read Essay","entry":true}],"content_path":"content/B59-0073"},{"id":"B59-0074","title":"Smart Contracts (1994 Original)","author":"Nick Szabo","date":"1994-01-01","type":"writing","description":"The original 1994 essay where Szabo first defined \"smart contracts\" - the term and concept that has shaped decades of subsequent work. This is the foundational text of the entire smart contracts field.","citation":"Szabo, N. (1994). \"Smart Contracts (1994 Original).\" Retrieved from https://szabo.best.vwh.net/smart.contracts.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/smart.contracts.html","hash":"99b6465362ddf9656ded2f749418c4bc365e76715dee248eaa63a16f4ae11392","tags":["nick-szabo","cypherpunks","primary-source","smart-contracts"],"excerpt":null,"files":[{"path":"smart-contracts-1994.html","size":9199,"label":"Read Essay","entry":true}],"content_path":"content/B59-0074"},{"id":"B59-0075","title":"Smart Contracts: Building Blocks for Digital Markets","author":"Nick Szabo","date":"1996-01-01","type":"writing","description":"Szabo's 1996 elaboration of smart contracts as building blocks for digital markets. Lays out the components needed for a functioning digital contract system - the protocols, the trust relationships, and the architectural decisions that would later inform blockchain platforms.","citation":"Szabo, N. (1996). \"Smart Contracts: Building Blocks for Digital Markets.\" Retrieved from https://szabo.best.vwh.net/smart_contracts_2.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net (the original site, now defunct). Original URL: https://szabo.best.vwh.net/smart_contracts_2.html","hash":"5c601413af215c614675122142c4c985fd044ea2c231f7b35e0ff1e0c4c03d7a","tags":["nick-szabo","cypherpunks","primary-source","smart-contracts"],"excerpt":null,"files":[{"path":"smart-contracts-1996.html","size":55485,"label":"Read Essay","entry":true}],"content_path":"content/B59-0075"},{"id":"B59-0076","title":"Delegation and Agreement Based Certification Policy","author":"Nick Szabo","date":"1997-01-01","type":"writing","description":"Szabo's framework for delegation and agreement-based certification - how authority can be delegated and certified in a distributed system without relying on a central certificate authority.","citation":"Szabo, N. (1997). \"Delegation and Agreement Based Certification Policy.\" Retrieved from https://nakamotoinstitute.org/library/delegation-and-agreement-based-certification-policy/.","provenance":"Retrieved from the Satoshi Nakamoto Institute Library at https://nakamotoinstitute.org/library/delegation-and-agreement-based-certification-policy/.","hash":"2b7053be945ed8232810972402eb4ba51fb48e1e8696c1b1eab18b436e9e0646","tags":["nick-szabo","cypherpunks","primary-source"],"excerpt":null,"files":[{"path":"delegation-agreement-cert.html","size":64068,"label":"Read Essay","entry":true}],"content_path":"content/B59-0076"},{"id":"B59-0077","title":"Wet Code and Dry","author":"Nick Szabo","date":"2006-11-26","type":"writing","description":"Szabo's influential blog post distinguishing \"wet code\" (interpretation by human judges and lawyers) from \"dry code\" (executable computer code). Argues that the boundary between the two is one of the most consequential design questions in any legal-technical system.","citation":"Szabo, N. (2006). \"Wet Code and Dry.\" Retrieved from https://unenumerated.blogspot.com/2006/11/wet-code-and-dry.html.","provenance":"Retrieved from Szabo's Unenumerated blog at https://unenumerated.blogspot.com/2006/11/wet-code-and-dry.html.","hash":"7b2f241a7cae1f37aa58d7a963265cff7ee6a7c369070bf60511d8093e584d98","tags":["nick-szabo","cypherpunks","primary-source","legal-theory","blog-post"],"excerpt":null,"files":[{"path":"wet-code-and-dry.html","size":73065,"label":"Read Essay","entry":true}],"content_path":"content/B59-0077"},{"id":"B59-0078","title":"JAN3 Welcomes Nick Szabo as Chief Scientist","author":"Nick Szabo","date":"2025-01-22","type":"writing","description":"Announcement post from JAN3 (Samson Mow's Bitcoin-focused company) welcoming Nick Szabo as Chief Scientist in January 2025. Marks a new phase of Szabo's public work and represents his continued involvement in Bitcoin-related research.","citation":"Szabo, N. (2025). \"JAN3 Welcomes Nick Szabo as Chief Scientist.\" Retrieved from https://jan3.com/blog/jan3-welcomes-nick-szabo-as-chief-scientist.","provenance":"Retrieved directly from JAN3's blog at https://jan3.com/blog/jan3-welcomes-nick-szabo-as-chief-scientist.","hash":"8e21976680dff5b26fc73534a3a1e472c69035ab2cb66cf1f59bd3b9e93bdc3f","tags":["nick-szabo","cypherpunks","primary-source","blog-post","jan3"],"excerpt":null,"files":[{"path":"jan3-welcomes-szabo.html","size":97582,"label":"Read Essay","entry":true}],"content_path":"content/B59-0078"},{"id":"B59-0079","title":"The Fabric of Desires","author":"Nick Szabo","date":"2025-02-01","type":"writing","description":"One of Szabo's first essays published under his role at JAN3. A philosophical piece exploring the relationship between human desires, institutions, and the technologies that mediate between them.","citation":"Szabo, N. (2025). \"The Fabric of Desires.\" Retrieved from https://jan3.com/blog/the-fabric-of-desires.","provenance":"Retrieved directly from JAN3's blog at https://jan3.com/blog/the-fabric-of-desires.","hash":"218a6316385582bafc09b8745bb7bb9152d0394292213b24dead18e2173bb797","tags":["nick-szabo","cypherpunks","primary-source","blog-post","jan3"],"excerpt":null,"files":[{"path":"fabric-of-desires.html","size":97273,"label":"Read Essay","entry":true}],"content_path":"content/B59-0079"},{"id":"B59-0080","title":"Scarce Objects","author":"Nick Szabo","date":"2003-01-01","type":"writing","description":"Szabo's essay on the concept of scarce objects — digital or physical items whose value derives from their unforgeable scarcity. Explores how cryptographic and institutional mechanisms can create and protect scarcity in digital environments, a foundational concept in the intellectual genealogy of Bitcoin.","citation":"Szabo, N. (c. 2003). Scarce Objects. Retrieved from http://web.archive.org/web/20160417231212/http://szabo.best.vwh.net/scarce.html.","provenance":"Retrieved from Wayback Machine archive of Szabo's personal essay site szabo.best.vwh.net (archived 2016). Original URL: http://szabo.best.vwh.net/scarce.html.","hash":"a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2","tags":["nick-szabo","primary-source","smart-contracts","scarcity","digital-property","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"http://web.archive.org/web/20160417231212/http://szabo.best.vwh.net/scarce.html","size":0,"label":"Read Essay (Wayback Machine)","entry":true,"external":true}],"content_path":"content/B59-0080"},{"id":"B59-0081","title":"The Playdough Protocols","author":"Nick Szabo","date":"2001-01-01","type":"writing","description":"Szabo's essay on the cryptographic and institutional design of bearer instruments — physical and digital tokens that function like clay tablets, vouchers, or promissory notes. Explores how trust, physical form, and cryptographic verification can be combined in protocols for transferring value without a central authority.","citation":"Szabo, N. (c. 2001). The Playdough Protocols. Retrieved from https://nakamotoinstitute.org/library/the-playdough-protocols/.","provenance":"Retrieved from the Satoshi Nakamoto Institute library. Original source: szabo.best.vwh.net/clay.html.","hash":"b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3","tags":["nick-szabo","primary-source","smart-contracts","bearer-instruments","cryptography","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"https://nakamotoinstitute.org/library/the-playdough-protocols/","size":0,"label":"Read Essay (SNI)","entry":true,"external":true}],"content_path":"content/B59-0081"},{"id":"B59-0082","title":"A Measure of Sacrifice","author":"Nick Szabo","date":"2001-01-01","type":"writing","description":"Szabo's essay on the concept of proof of work as a measure of sacrifice — exploring how time, energy, and computation can serve as a trustworthy signal of commitment and value. A conceptual precursor to Bitcoin's proof-of-work mechanism, framed through the history of labor contracts and synchronization protocols.","citation":"Szabo, N. (c. 2001). A Measure of Sacrifice. Retrieved from https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/synch.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net. Original filename: synch.html.","hash":"c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4","tags":["nick-szabo","primary-source","proof-of-work","sacrifice","time","digital-property","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/synch.html","size":0,"label":"Read Essay (UvA Mirror)","entry":true,"external":true}],"content_path":"content/B59-0082"},{"id":"B59-0083","title":"The Abuse of Statistics in Cryptography","author":"Nick Szabo","date":"1999-01-01","type":"writing","description":"Szabo's technical critique of how statistical arguments are misused in cryptographic analysis and security claims. Examines common fallacies in probabilistic security arguments and the epistemological standards that should apply to cryptographic proof.","citation":"Szabo, N. (c. 1999). The Abuse of Statistics in Cryptography. Retrieved from https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/statistics.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net. Original filename: statistics.html (also referenced as abuse.html on the site index).","hash":"d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5","tags":["nick-szabo","primary-source","cryptography","statistics","security","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/statistics.html","size":0,"label":"Read Essay (UvA Mirror)","entry":true,"external":true}],"content_path":"content/B59-0083"},{"id":"B59-0084","title":"Resources for the History of Commercial Law and Governance","author":"Nick Szabo","date":"2002-01-01","type":"writing","description":"Szabo's curated bibliography and annotated link collection covering the history of commercial law, the Law Merchant (lex mercatoria), Brehon law, medieval trade institutions, and the origins of property rights and contract enforcement. A key research aid for understanding the historical institutional parallels Szabo draws throughout his smart contracts work.","citation":"Szabo, N. (c. 2002). Resources for the History of Commercial Law and Governance. Retrieved from https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/lawlinks.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net. Original filename: lawlinks.html (also referenced as commercial.html on the site index).","hash":"e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6","tags":["nick-szabo","primary-source","commercial-law","legal-history","lex-mercatoria","brehon-law","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/lawlinks.html","size":0,"label":"Read Essay (UvA Mirror)","entry":true,"external":true}],"content_path":"content/B59-0084"},{"id":"B59-0085","title":"Smart Contracts Glossary","author":"Nick Szabo","date":"1995-01-01","type":"writing","description":"Szabo's definitive glossary of terms used in his smart contracts framework. Defines concepts including smart contract, contracting, performance, breach, wet code, dry code, and related legal and cryptographic terms. An essential reference for understanding the precise vocabulary of Szabo's work.","citation":"Szabo, N. (c. 1995). Smart Contracts Glossary. Retrieved from https://nakamotoinstitute.org/library/smart-contracts-glossary/.","provenance":"Retrieved from the Satoshi Nakamoto Institute library. Also available at the UvA mirror: szabo.best.vwh.net/smart_contracts_glossary.html.","hash":"f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1","tags":["nick-szabo","primary-source","smart-contracts","glossary","legal-theory","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"https://nakamotoinstitute.org/library/smart-contracts-glossary/","size":0,"label":"Read Essay (SNI)","entry":true,"external":true}],"content_path":"content/B59-0085"},{"id":"B59-0086","title":"Multinational Small Business","author":"Nick Szabo","date":"1999-01-01","type":"writing","description":"Szabo's essay on how cryptographic protocols and smart contracts could enable small businesses to operate across international borders without reliance on traditional financial intermediaries or national legal systems. Explores the implications of digital cash and self-enforcing contracts for global microcommerce.","citation":"Szabo, N. (c. 1999). Multinational Small Business. Retrieved from https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/multi.small.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net. Original filename: multi.small.html.","hash":"a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b3","tags":["nick-szabo","primary-source","smart-contracts","digital-cash","international-commerce","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/multi.small.html","size":0,"label":"Read Essay (UvA Mirror)","entry":true,"external":true}],"content_path":"content/B59-0086"},{"id":"B59-0087","title":"Credit with Privity","author":"Nick Szabo","date":"1995-01-01","type":"writing","description":"Szabo's analysis of how cryptographic protocols can implement credit relationships while preserving the legal concept of privity — the principle that only the parties to a contract are bound by its terms. Explores how digital cash and smart contracts can create credit without the liability and disclosure problems of traditional credit instruments.","citation":"Szabo, N. (c. 1995). Credit with Privity. Retrieved from https://nakamotoinstitute.org/library/credit-with-privity/.","provenance":"Retrieved from the Satoshi Nakamoto Institute library. Original source: szabo.best.vwh.net/creditpriv.html.","hash":"b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c4","tags":["nick-szabo","primary-source","smart-contracts","credit","privity","legal-theory","digital-cash","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"https://nakamotoinstitute.org/library/credit-with-privity/","size":0,"label":"Read Essay (SNI)","entry":true,"external":true}],"content_path":"content/B59-0087"},{"id":"B59-0088","title":"Privacy Marketing","author":"Nick Szabo","date":"1999-01-01","type":"writing","description":"Szabo's essay on the commercial and strategic incentives for businesses to offer privacy-preserving services. Argues that privacy can be a competitive differentiator in markets and explores how cryptographic tools can enable privacy-respecting marketing models that avoid the surveillance economy.","citation":"Szabo, N. (c. 1999). Privacy Marketing. Retrieved from https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/privacy_marketing.html.","provenance":"Retrieved from the University of Amsterdam mirror of szabo.best.vwh.net. Original filename: privacy_marketing.html.","hash":"c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d5","tags":["nick-szabo","primary-source","privacy","digital-markets","cryptography","szabo.best.vwh.net"],"excerpt":null,"files":[{"path":"https://www.fon.hum.uva.nl/rob/Courses/InformationInSpeech/CDROM/Literature/LOTwinterschool2006/szabo.best.vwh.net/privacy_marketing.html","size":0,"label":"Read Essay (UvA Mirror)","entry":true,"external":true}],"content_path":"content/B59-0088"},{"id":"B59-0089","title":"APh Technology Game Designers, circa 1978","author":"Photograph from the collection of David Rolfe","date":"1978","type":"image","description":"Photograph of the APh Technology Consultants game-design team in Pasadena, California, circa 1978, during the early development of Mattel's Intellivision. Left to right: Hal Finney, David Rolfe, and Will McCown (a hardware engineer, not a game designer). The image -- captioned 'Game Design circa 1978' -- documents the shoestring working environment (note the bicycle and cinder-block shelving) in which Finney and Rolfe programmed some of the first Intellivision titles, years before Finney's later work on PGP, anonymous remailers, and Bitcoin.","citation":"Rolfe, D. (photographer). 'Game Design circa 1978' [Photograph]. Uploaded 11 March 2018 to the personal album 'Dave's images'. From the collection of David Rolfe.","provenance":"Screen capture of David Rolfe's personal photo-album page showing the original circa-1978 photograph and its caption. Rolfe identifies the subjects, left to right, as Hal Finney, David Rolfe, and Will McCown. Preserved as a primary visual record of Finney's early career at APh Technology Consultants.","hash":"4c5a9d4e0480b0cc5c55a506db2129e16b7a2aca2c2d469b0f02decc35853f50","tags":["hal-finney","david-rolfe","aph","intellivision","atari","game-design","photograph","gaming","video-games","mattel"],"excerpt":"From left to right, Hal Finney, David Rolfe, Will McCown (a hardware guy, not a game designer). This would have been the era of early Intellivision development.","files":[{"path":"aph-game-designers-1978.jpg","size":351610,"label":"View Photograph","entry":true}],"content_path":"content/B59-0089"},{"id":"B59-0090","title":"Hal Finney Interview (Atari Compendium)","author":"Hal Finney, interviewed by Scott Stilphen","date":"2006","type":"writing","description":"Interview with Hal Finney conducted by Scott Stilphen for the Atari Compendium, recounting Finney's early career as a programmer at APh Technology Consultants -- the Pasadena firm hired by Mattel in 1976 to help design the Intellivision system. Finney discusses developing some of the first Intellivision, M Network, and Keyboard Component games, including Atari 2600 titles such as 'Adventures of Tron' and 'Astroblast', alongside the APh team led by Glenn Hightower, well before his pioneering cryptography work on PGP, remailers, and Bitcoin.","citation":"Stilphen, S. (2006). 'Hal Finney interview.' Atari Compendium. https://www.ataricompendium.com/archives/interviews/hal_finney/interview_hal_finney.html","provenance":"MHT web archive captured from the Atari Compendium (ataricompendium.com). Preserved as a primary-source interview documenting Hal Finney's early video-game programming career.","hash":"1cdd6f18cf3f7ca876554e9f8056e1a62132d021664d8113be6e15e64f6f8ab4","tags":["hal-finney","atari","intellivision","aph","game-design","interview","scott-stilphen","gaming","video-games","mattel","speech-synthesis","baseball","major-league-baseball"],"excerpt":"As the story goes, APh Technology Consultants (located in Pasadena, CA) was hired by Mattel in 1976 to help design what became the Intellivision system.","files":[{"path":"hal-finney-atari-interview.html","size":1764011,"label":"Read Interview (MHT Archive)","entry":true}],"content_path":"content/B59-0090"},{"id":"B59-0091","title":"David Rolfe Interview (Digital Press)","author":"David Rolfe, interviewed by Scott Stilphen","date":"2006","type":"writing","description":"Interview with programmer David Rolfe conducted by Scott Stilphen for Digital Press, tracing Rolfe's path from a Caltech engineering degree (1977) into early console-game development at APh Technology Consultants, where he worked alongside Hal Finney on Intellivision, Atari VCS/2600 (M-Network), and other titles. A first-hand account of the same APh milieu that shaped Finney's formative programming years.","citation":"Stilphen, S. 'DP Interviews... David Rolfe.' Digital Press. https://www.digitpress.com/library/interviews/interview_david_rolfe.html","provenance":"MHT web archive captured from Digital Press (digitpress.com). The interview itself is undated; it is attributed to Scott Stilphen's mid-2000s interview series and dated here to that era. Preserved as a primary-source interview documenting the APh game-design team that included Hal Finney.","hash":"9756570d5ff2c95ad4b2ad75b76cc91baaacb46cb295b162dbbc6fdb3adfd3b2","tags":["david-rolfe","hal-finney","aph","intellivision","atari","game-design","interview","caltech","gaming","video-games","mattel"],"excerpt":"To say David Rolfe is a multi-talented programmer is a little like saying the sun is hot. Without a doubt, he's been there, done that.","files":[{"path":"david-rolfe-interview.html","size":436483,"label":"Read Interview (MHT Archive)","entry":true}],"content_path":"content/B59-0091"},{"id":"B59-0092","title":"The SSL Challenge: Solution Announcement","author":"Damien Doligez","date":"1995-08-15","type":"writing","description":"PGP-signed announcement by Damien Doligez (INRIA) reporting the successful brute-force solution of the SSL encryption challenge that Hal Finney posted on 17 July 1995. Using roughly 120 workstations and several parallel computers across INRIA, Ecole Polytechnique, and ENS, Doligez recovered the 40-bit export-grade secret key (7e f0 96 1f a6) after scanning about half the key space in eight days, demonstrating that export-strength SSL was trivially breakable. The decrypted payload is a sample Netscape Commerce order famously addressed to 'Mr Cosmic Kumquat, SSL Trusters Inc., 1234 Squeamish Ossifrage Road.' A landmark Crypto Wars result and a direct answer to Finney's challenge.","citation":"Doligez, D. (1995, August). 'SSL challenge -- broken.' PGP-signed announcement. Archived at http://pauillac.inria.fr/~doligez/ssl/announce.txt","provenance":"Plain-text, PGP-signed message (PGP 2.6.2) announcing the solution to Hal Finney's SSL challenge of 17 July 1995, including an appended PGP timestamp. Preserved as a primary source from the Crypto Wars era. Companion to record B59-0040 ('The SSL Challenge').","hash":"01861c7ea085905bfce331b6dfd7c5a9624e8fd438bf93b970325cdfdd768c3d","tags":["hal-finney","ssl","crypto-wars","cryptography","brute-force","netscape","cypherpunks","pgp"],"excerpt":"The 40-bit secret part of the key is 7e f0 96 1f a6. I found it by a brute force search on a network of about 120 workstations and a few parallel computers at INRIA, Ecole Polytechnique, and ENS.","files":[{"path":"ssl-challenge-solution-announcement.txt","size":5711,"label":"Read Announcement (PGP-Signed)","entry":true}],"content_path":"content/B59-0092"},{"id":"B59-0093","title":"Bitcoin's Earliest Adopter Is Cryonically Freezing His Body to See the Future","author":"Andy Greenberg (WIRED)","date":"2014-08-29","type":"writing","description":"WIRED feature by Andy Greenberg on Hal Finney -- recipient of the first Bitcoin transaction and one of Bitcoin's earliest contributors -- written shortly after his death from ALS in August 2014. The article recounts Finney's decision to be cryonically preserved by the Alcor Life Extension Foundation, his wife Fran's reflections on his lifelong optimism about technology and the future, and his hope that scientific advances might one day allow his revival.","citation":"Greenberg, A. (2014, August 29). 'Bitcoin's Earliest Adopter Is Cryonically Freezing His Body to See the Future.' WIRED. https://www.wired.com/2014/08/hal-finney/","provenance":"MHT web archive of the WIRED article (wired.com/2014/08/hal-finney). Preserved as a secondary-source profile documenting Hal Finney's cryopreservation at Alcor.","hash":"f1522ecc4be23b2676b2d0fa5e39eac99cbb47a5071a8b987573399d35d5f38b","tags":["hal-finney","cryonics","alcor","bitcoin","als","wired","andy-greenberg","obituary"],"excerpt":"He's always been optimistic about the future, says Hal Finney's wife, Fran. Every new advance, he embraced it, every new technology. Hal relished life, and he made the most of everything.","files":[{"path":"bitcoins-earliest-adopter-cryonics.html","size":1496478,"label":"Read Article (MHT Archive)","entry":true}],"content_path":"content/B59-0093"},{"id":"B59-0094","title":"Frozen Heads and Future Fortunes: What Is the Cost of Digital Information?","author":"Finn Brunton (BBC Science Focus)","date":"2019-08-31","type":"writing","description":"BBC Science Focus essay by Finn Brunton telling the story of economist Phil Salin -- founder of the early online marketplace AMIX -- whose life and death intertwined sugar-based 'rocket candy', digital information exchanges, and cryonic preservation. The piece explores the long-running cypherpunk and extropian fascination with information, value, and preservation of the self, themes central to the milieu that produced Hal Finney and the first experiments in digital cash.","citation":"Brunton, F. (2019, August 31). 'Frozen heads and future fortunes: what is the cost of digital information?' BBC Science Focus Magazine. https://www.sciencefocus.com/future-technology/frozen-heads-and-future-fortunes-what-is-the-cost-of-digital-information","provenance":"MHT web archive of the BBC Science Focus Magazine article. Preserved as a secondary source on cryonics, digital-information markets, and the extropian context surrounding Project B59's subjects.","hash":"07b87586ac9f06388629d52b92f989f57dc2ec9234e716ac8e5d8bf67756eebc","tags":["phil-salin","cryonics","extropians","digital-cash","amix","finn-brunton","bbc-science-focus"],"excerpt":"Finn Brunton tells the story of economist Phil Salin, a man whose life (and death) involved sugar-based 'rocket candy', digital information exchanges, and frozen heads.","files":[{"path":"frozen-heads-and-future-fortunes.html","size":1433224,"label":"Read Article (MHT Archive)","entry":true}],"content_path":"content/B59-0094"},{"id":"B59-0095","title":"Cryonics Magazine -- Member Profile: Hal Finney (Vol 40, Issue 2)","author":"Alcor Life Extension Foundation","date":"2019-06-14","type":"writing","description":"Second-quarter 2019 issue of Cryonics, the magazine of the Alcor Life Extension Foundation (Vol 40, Issue 2), featuring a special post-cryopreservation Member Profile of Hal Finney. Marking Bitcoin's tenth anniversary and Finney's historic 'Running bitcoin' tweet, the profile honors the cryptographer, cypherpunk, PGP developer, anonymous-remailer pioneer, early console-game programmer, and first recipient of a Bitcoin transaction, and was created with the support of his wife and children. The 60-page issue also includes Case Report A-1990 and an essay on Victor Frankenstein.","citation":"Alcor Life Extension Foundation. (2019). 'Member Profile: Hal Finney.' Cryonics, 40(2), 2nd Quarter 2019. https://www.alcor.org","provenance":"PDF of Cryonics magazine, 2nd Quarter 2019 (Vol 40, Issue 2), published by the Alcor Life Extension Foundation (60 pages; file produced 14 June 2019). Preserved as a primary-source biographical profile of Hal Finney.","hash":"8e5c4b0f06e10c4d90271027b59cc1f1650d3f1e6af42afe940bbfa3d9d10378","tags":["hal-finney","cryonics","alcor","bitcoin","pgp","member-profile","extropians"],"excerpt":null,"files":[{"path":"cryonics-magazine-hal-finney-profile.pdf","size":2937454,"label":"Read Magazine (PDF)","entry":true}],"content_path":"content/B59-0095"},{"id":"B59-0096","title":"Pricing via Processing, or Combatting Junk Mail","author":"Cynthia Dwork & Moni Naor","date":"1992-08-16","type":"writing","description":"The paper that invented proof-of-work. Presented at CRYPTO ’92, Dwork and Naor propose deterring junk mail and resource abuse by requiring the sender to compute a moderately hard, but not intractable, function before a message is accepted — a \"pricing function.\" Honest users barely notice the cost; bulk abusers are priced out. Hashcash (1997), b-money, RPOW and Bitcoin mining all descend directly from this idea.","citation":"Cynthia Dwork and Moni Naor, \"Pricing via Processing, or Combatting Junk Mail,\" Advances in Cryptology — CRYPTO ’92, LNCS 740, Springer, pp. 139–147.","provenance":"Republished from the CRYPTO ’92 proceedings; author manuscripts hosted at the Weizmann Institute and Microsoft Research.","hash":"","tags":["proof-of-work","cryptography","digital-cash","cynthia-dwork","moni-naor","spam","pricing-function","crypto-1992","primary-source","bitcoin-precursor"],"excerpt":"\"In order to send a message, the sender must compute some moderately expensive, but not intractable, function of the message and some additional information.\"","files":[],"content_path":"content/B59-0096","local":["content/B59-0096/pricing-via-processing.html"]}];
